    /** 양방향 등록 */
    private static void r(String a, String b, int trips) {
        TABLE.put(a + "->" + b, trips);
        TABLE.put(b + "->" + a, trips);
    }

    /** 노선 운행 편수 조회. 없으면 -1 */
    public static int lookup(String from, String to) {
        return TABLE.getOrDefault(from + "->" + to, -1);
    }

    private BusFrequencyTable() {}
